// Fetch latest fb-post-* Gist (Code node — bypasses HTTP node sendHeaders schema bug)
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.github.com/gists?per_page=10',
  headers: {
    'Authorization': 'token ' + $env.GIST_PAT,
    'Accept': 'application/vnd.github+json',
    'User-Agent': 'n8n-content-orchestrator'
  },
  json: true
});

const arr = Array.isArray(response) ? response : [];
const fbGist = arr.find(g => (g.description || '').startsWith('fb-post-'));
if (!fbGist) {
  throw new Error('No fb-post-* Gist found in latest 10. Cloud routine 沒寫 Gist? Available: ' + arr.slice(0, 3).map(g => g.description || '(no desc)').join(' | '));
}
const fileEntry = Object.values(fbGist.files)[0];
return [{
  json: {
    gist_id: fbGist.id,
    gist_html_url: fbGist.html_url,
    raw_url: fileEntry.raw_url,
    filename: fileEntry.filename,
    description: fbGist.description,
    created_at: fbGist.created_at
  }
}];

// Parse YAML frontmatter + extract draft
const raw = $input.first().json.data || $input.first().json;
const rawText = typeof raw === 'string' ? raw : JSON.stringify(raw);

const fmMatch = rawText.match(/^---\s*\n([\s\S]*?)\n---\s*\n([\s\S]*)$/);
if (!fmMatch) throw new Error('No YAML frontmatter found in Gist content');

const fmText = fmMatch[1];
const body = fmMatch[2];

// Simple YAML parser (flat keys + arrays)
const meta = {};
fmText.split('\n').forEach(line => {
  const m = line.match(/^([a-z_]+):\s*(.*)$/);
  if (m) {
    let val = m[2].trim();
    if (val.startsWith('[') && val.endsWith(']')) {
      val = val.slice(1, -1).split(',').map(s => s.trim().replace(/^["']|["']$/g, '')).filter(s => s);
    } else if (val.startsWith('"') && val.endsWith('"')) {
      val = val.slice(1, -1);
    } else if (!isNaN(val) && val !== '') {
      val = Number(val);
    }
    meta[m[1]] = val;
  }
});

const draftMatch = body.match(/##\s*(?:草稿|draft)\s*\n([\s\S]*?)(?=\n##\s|$)/i);
let draft = draftMatch ? draftMatch[1].trim() : body.trim();

return [{
  json: {
    metadata: meta,
    post_text: draft,
    post_text_chars: draft.length,
    format: meta.format || 'text',
    gist_id: $('Pick Latest fb-post Gist').first().json.gist_id,
    gist_url: $('Pick Latest fb-post Gist').first().json.gist_html_url
  }
}];

// Resolve image priority: Drive folder scan (NEW unprocessed) → Pollinations.ai fallback
// Dedup uses $workflow.staticData (auto-persists across runs, no fs required)
const meta = $input.first().json.metadata;
const upstream = $input.first().json;
const topic = meta.image_topic_for_gen || meta.topic;

let image_base64 = null;
let image_source = 'none';
let image_error = null;
let drive_file_used = null;

const wfData = $getWorkflowStaticData('global');
wfData.processed_drive_ids = wfData.processed_drive_ids || [];

try {
  // ---- Step 1: Drive folder scan (priority) ----
  if ($env.DRIVE_API_KEY && $env.DRIVE_INBOX_FOLDER_ID) {
    const listResp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.googleapis.com/drive/v3/files',
      qs: {
        q: `'${$env.DRIVE_INBOX_FOLDER_ID}' in parents and trashed=false and mimeType contains 'image/'`,
        key: $env.DRIVE_API_KEY,
        fields: 'files(id,name,mimeType,createdTime)',
        orderBy: 'createdTime'
      },
      json: true
    });
    const files = (listResp.files || []).filter(f => f.mimeType && f.mimeType.startsWith('image/'));
    if (files.length > 0) {
      const fresh = files.find(f => !wfData.processed_drive_ids.includes(f.id));
      if (fresh) {
        const buf = await this.helpers.httpRequest({
          method: 'GET',
          url: `https://www.googleapis.com/drive/v3/files/${fresh.id}?alt=media&key=${$env.DRIVE_API_KEY}`,
          encoding: 'arraybuffer',
          json: false,
          returnFullResponse: false
        });
        image_base64 = Buffer.from(buf).toString('base64');
        image_source = `drive:${fresh.id}`;
        drive_file_used = { id: fresh.id, name: fresh.name };
        wfData.processed_drive_ids.push(fresh.id);
      }
    }
  }

  // ---- Step 2: Pollinations.ai fallback (with Chinese→English translation) ----
  if (!image_base64 && topic) {
    let imagePrompt = typeof topic === 'string' ? topic : String(topic);
    // If topic contains Chinese chars, translate to English image prompt via Pollinations text endpoint
    if (/[\u4e00-\u9fff]/.test(imagePrompt)) {
      try {
        const translateInstr = `Translate this into a concise English image generation prompt (visual description only, no quotes, max 30 words): ${imagePrompt}`;
        const tResp = await this.helpers.httpRequest({
          method: 'GET',
          url: 'https://text.pollinations.ai/' + encodeURIComponent(translateInstr),
          json: false,
          returnFullResponse: false,
          timeout: 30000
        });
        const translated = (typeof tResp === 'string' ? tResp : String(tResp)).trim();
        if (translated && translated.length < 400 && translated.length > 5) {
          imagePrompt = translated;
        }
      } catch (e) { /* fallback to original */ }
    }
    const prompt = imagePrompt + ', professional photography style, clean composition, no text overlay';
    const url = `https://image.pollinations.ai/prompt/${encodeURIComponent(prompt)}?width=1024&height=1024&model=flux&nologo=true&safe=true`;
    const buf = await this.helpers.httpRequest({
      method: 'GET',
      url,
      encoding: 'arraybuffer',
      json: false,
      returnFullResponse: false,
      timeout: 60000
    });
    image_base64 = Buffer.from(buf).toString('base64');
    image_source = 'pollinations.ai:flux';
    image_error = `prompt_used: ${imagePrompt.slice(0, 100)}`;
  }

  if (!image_base64) {
    image_error = 'No new Drive image and no topic for fallback';
  }
} catch (e) {
  image_error = e.message;
}

return [{
  json: {
    ...upstream,
    image_base64,
    image_source,
    image_error,
    has_image: !!image_base64,
    drive_file_used,
    processed_count: wfData.processed_drive_ids.length
  }
}];

// Upload image to ImgBB (anonymous) → public URL for IG/Threads to fetch
// Note: env var named IMGUR_CLIENT_ID for compatibility, value is ImgBB API key
const upstream = $input.first().json;
const { image_base64, has_image } = upstream;

let image_url = null;
let imgur_id = null;
let imgur_error = null;

if (has_image && $env.IMGUR_CLIENT_ID) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.imgbb.com/1/upload?key=${$env.IMGUR_CLIENT_ID}`,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: { image: image_base64 },
      json: true
    });
    if (resp && resp.success && resp.data) {
      image_url = resp.data.url || (resp.data.image && resp.data.image.url);
      imgur_id = resp.data.id;
    } else {
      imgur_error = 'ImgBB returned non-success: ' + JSON.stringify(resp).slice(0, 500);
    }
  } catch (e) {
    imgur_error = e.message;
  }
} else if (!has_image) {
  imgur_error = 'no image to upload';
} else {
  imgur_error = 'IMGUR_CLIENT_ID (ImgBB) not set';
}

// Strip image_base64 from downstream output to keep payload small
const { image_base64: _strip, ...rest } = upstream;
return [{
  json: {
    ...rest,
    image_url,
    imgur_id,
    imgur_error
  }
}];

// Publish to FB Page: photo if image_url, else text-only
const upstream = $input.first().json;
const { post_text, image_url } = upstream;
const V = $env.FB_GRAPH_VERSION || 'v24.0';
const PAGE_ID = $env.FB_PAGE_ID;
const SYS_TOKEN = $env.FB_SYSTEM_USER_TOKEN;

let fb_result = { success: false };

try {
  // Step 1: exchange page-scoped token
  const accounts = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://graph.facebook.com/${V}/me/accounts`,
    qs: { fields: 'id,name,access_token', limit: 100, access_token: SYS_TOKEN },
    json: true
  });
  const page = (accounts.data || []).find(p => String(p.id) === String(PAGE_ID));
  if (!page) throw new Error(`Page ${PAGE_ID} not in /me/accounts`);
  const pageToken = page.access_token;

  // Step 2: post (photo if image, else feed)
  let post;
  if (image_url) {
    post = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/${V}/${PAGE_ID}/photos`,
      body: { url: image_url, caption: post_text, access_token: pageToken },
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      json: true
    });
  } else {
    post = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/${V}/${PAGE_ID}/feed`,
      body: { message: post_text, access_token: pageToken },
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      json: true
    });
  }

  const postId = post.post_id || post.id || '';
  const [pageNum, postPart] = (postId || '').split('_');
  fb_result = {
    success: true,
    post_id: postId,
    permalink: postPart ? `https://www.facebook.com/${pageNum}/posts/${postPart}` : `https://www.facebook.com/${PAGE_ID}`,
    type: image_url ? 'photo' : 'text'
  };
} catch (e) {
  fb_result = { success: false, error: e.message };
}

return [{ json: { ...upstream, fb_result } }];

// Publish to Instagram (requires image_url + IG_BUSINESS_ACCOUNT_ID + system user token)
const upstream = $input.first().json;
const { post_text, image_url, metadata } = upstream;
const V = $env.FB_GRAPH_VERSION || 'v24.0';
const IG_ID = $env.IG_BUSINESS_ACCOUNT_ID;
const SYS_TOKEN = $env.FB_SYSTEM_USER_TOKEN;

let ig_result = { success: false, skipped: false };

if (!image_url) {
  ig_result = { success: false, skipped: true, reason: 'IG requires image, none resolved' };
} else if (!IG_ID || !SYS_TOKEN) {
  ig_result = { success: false, skipped: true, reason: 'IG env not configured' };
} else {
  try {
    // Build caption (post text + hashtags from metadata.tags)
    const tags = (metadata && Array.isArray(metadata.tags)) ? metadata.tags.map(t => '#' + String(t).replace(/^#/, '')).join(' ') : '';
    const caption = tags ? (post_text + '\n\n' + tags) : post_text;

    // Step 1: create media container
    const container = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/${V}/${IG_ID}/media`,
      qs: {
        image_url: image_url,
        caption: caption,
        access_token: SYS_TOKEN
      },
      json: true
    });
    const creationId = container.id;
    if (!creationId) throw new Error('No creation_id from /media: ' + JSON.stringify(container).slice(0, 300));

    // Step 2: poll status (up to ~30s)
    let status = 'IN_PROGRESS';
    for (let i = 0; i < 10; i++) {
      await new Promise(r => setTimeout(r, 3000));
      const statusResp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://graph.facebook.com/${V}/${creationId}`,
        qs: { fields: 'status_code', access_token: SYS_TOKEN },
        json: true
      });
      status = statusResp.status_code;
      if (status === 'FINISHED') break;
      if (status === 'ERROR') throw new Error('IG container error: ' + JSON.stringify(statusResp));
    }
    if (status !== 'FINISHED') throw new Error('IG container not ready after polling: ' + status);

    // Step 3: publish
    const publishResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/${V}/${IG_ID}/media_publish`,
      qs: { creation_id: creationId, access_token: SYS_TOKEN },
      json: true
    });

    ig_result = {
      success: true,
      media_id: publishResp.id,
      permalink: `https://www.instagram.com/p/${publishResp.id}/`
    };
  } catch (e) {
    ig_result = { success: false, error: e.message };
  }
}

return [{ json: { ...upstream, ig_result } }];

// Publish to Threads with graceful 500-char truncation at sentence boundary
const upstream = $input.first().json;
const { post_text, image_url } = upstream;
const T_TOKEN = $env.THREADS_LONG_LIVED_TOKEN;
const T_USER = $env.THREADS_USER_ID;

let threads_result = { success: false, skipped: false };

// Truncate at sentence boundary, fallback to ellipsis. Default soft limit 480 to leave headroom.
function truncateThreads(text, max = 480) {
  if (!text) return '';
  if (text.length <= max) return text;
  const cut = text.slice(0, max);
  const boundaries = ['。', '. ', '！', '!', '？', '?', '\n\n', '\n'];
  let lastIdx = -1;
  for (const b of boundaries) {
    const idx = cut.lastIndexOf(b);
    if (idx > lastIdx) lastIdx = idx + b.length;
  }
  if (lastIdx > max * 0.6) return cut.slice(0, lastIdx).trim();
  return cut.slice(0, max - 3).trim() + '...';
}

if (!T_TOKEN || !T_USER) {
  threads_result = { success: false, skipped: true, reason: 'Threads env not configured (waiting for OAuth)' };
} else {
  try {
    const original = post_text || '';
    const text = truncateThreads(original, 480);
    const wasTruncated = original.length > text.length;
    const mediaType = image_url ? 'IMAGE' : 'TEXT';

    const containerQs = {
      media_type: mediaType,
      text: text,
      access_token: T_TOKEN
    };
    if (image_url) containerQs.image_url = image_url;

    const container = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.threads.net/v1.0/${T_USER}/threads`,
      qs: containerQs,
      json: true
    });
    const containerId = container.id;
    if (!containerId) throw new Error('No creation_id from Threads /threads: ' + JSON.stringify(container).slice(0, 300));

    await new Promise(r => setTimeout(r, image_url ? 5000 : 2000));

    const publishResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://graph.threads.net/v1.0/${T_USER}/threads_publish`,
      qs: { creation_id: containerId, access_token: T_TOKEN },
      json: true
    });

    threads_result = {
      success: true,
      thread_id: publishResp.id,
      type: mediaType,
      original_chars: original.length,
      published_chars: text.length,
      truncated: wasTruncated
    };
  } catch (e) {
    threads_result = { success: false, error: e.message };
  }
}

return [{ json: { ...upstream, threads_result } }];

// Aggregate final log
const u = $input.first().json;
return [{
  json: {
    timestamp: new Date().toISOString(),
    gist_id: u.gist_id,
    gist_url: u.gist_url,
    chars: u.post_text_chars,
    image: { source: u.image_source, has_image: u.has_image, error: u.image_error, url: u.image_url, imgur_error: u.imgur_error },
    fb: u.fb_result,
    ig: u.ig_result,
    threads: u.threads_result,
    summary: [
      u.fb_result && u.fb_result.success ? 'FB OK' : ('FB FAIL: ' + (u.fb_result && u.fb_result.error || 'unknown')),
      u.ig_result && u.ig_result.success ? 'IG OK' : (u.ig_result && u.ig_result.skipped ? 'IG SKIPPED' : ('IG FAIL: ' + (u.ig_result && u.ig_result.error || 'unknown'))),
      u.threads_result && u.threads_result.success ? 'Threads OK' : (u.threads_result && u.threads_result.skipped ? 'Threads SKIPPED' : ('Threads FAIL: ' + (u.threads_result && u.threads_result.error || 'unknown')))
    ].join(' | ')
  }
}];
